#include "protocol_topics.h"
#include <string.h>
static esp_err_t append_part(char *dst,size_t dst_len,const char *part){ size_t used,part_len; if(!dst||!part||dst_len==0)return ESP_ERR_INVALID_ARG; used=strlen(dst); part_len=strlen(part); if(used+part_len>=dst_len)return ESP_ERR_INVALID_SIZE; memcpy(dst+used,part,part_len+1); return ESP_OK; }
static esp_err_t build_topic(char *dst,size_t len,const char *base,const char *suffix){ if(!dst||!base||!suffix)return ESP_ERR_INVALID_ARG; dst[0]='\0'; ESP_ERROR_CHECK_WITHOUT_ABORT(append_part(dst,len,base)); return append_part(dst,len,suffix); }
esp_err_t protocol_topics_build(const app_mqtt_config_t *config, protocol_topic_bundle_t *topics){ if(!config||!topics||config->topic_prefix[0]=='\0'||config->device_id[0]=='\0')return ESP_ERR_INVALID_ARG; memset(topics,0,sizeof(*topics)); ESP_ERROR_CHECK_WITHOUT_ABORT(append_part(topics->base,sizeof(topics->base),config->topic_prefix)); ESP_ERROR_CHECK_WITHOUT_ABORT(append_part(topics->base,sizeof(topics->base),"/")); ESP_ERROR_CHECK_WITHOUT_ABORT(append_part(topics->base,sizeof(topics->base),config->device_id)); ESP_ERROR_CHECK_WITHOUT_ABORT(build_topic(topics->status,sizeof(topics->status),topics->base,"/status")); ESP_ERROR_CHECK_WITHOUT_ABORT(build_topic(topics->state,sizeof(topics->state),topics->base,"/state")); ESP_ERROR_CHECK_WITHOUT_ABORT(build_topic(topics->capabilities,sizeof(topics->capabilities),topics->base,"/capabilities")); ESP_ERROR_CHECK_WITHOUT_ABORT(build_topic(topics->commands,sizeof(topics->commands),topics->base,"/commands")); ESP_ERROR_CHECK_WITHOUT_ABORT(build_topic(topics->events,sizeof(topics->events),topics->base,"/events")); ESP_ERROR_CHECK_WITHOUT_ABORT(build_topic(topics->errors,sizeof(topics->errors),topics->base,"/errors")); ESP_ERROR_CHECK_WITHOUT_ABORT(build_topic(topics->schedules,sizeof(topics->schedules),topics->base,"/schedules")); return ESP_OK; }
